"""
MKT Christ-in-Every-Verse Commentary — Genesis chapters 10–12
Run: python3 scripts/zc-christ-genesis-10-12.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-christ/genesis.json (existing: chs 1–6 complete)

Key Christological decisions:
- Table of nations (ch10): primary connection is Acts 17:26 and the scope of
  Christ's redemption (Rev 5:9 — "from every tribe, language, people and nation").
  The 70 nations correspond to Jesus sending 70 disciples in Luke 10:1. Nimrod
  (vv8–12) treated as a type of human imperial power that Christ surpasses.
- Babel (11:1–9): primary connection is Pentecost (Acts 2) as the reversal —
  the scattered languages reunited under the gospel. "Make a name for ourselves"
  (11:4) vs. "the name above every name" given to Christ (Phil 2:9).
- Shem-to-Abram genealogy (11:10–32): Luke 3:34–36 traces Christ's lineage
  through Arphaxad → Shelah → Eber → Peleg → Reu → Serug → Nahor → Terah →
  Abraham. Every link in this chain is a link in the genealogy of Christ.
- Abrahamic covenant (12:1–3): Gal 3:8 calls 12:3 "the gospel in advance to
  Abraham"; Gal 3:16 identifies "your seed" as Christ; John 8:56 says Abraham
  "saw my day." This is the founding charter of the Messianic promise.
- "To your offspring I will give this land" (12:7): Gal 3:16 explicitly reads
  the singular "offspring/seed" as Christ — the land promise is the type of
  the inheritance Christ secures for all who are in him (Eph 1:14).
- Abram in Egypt (12:10–20): the Egypt episode prefigures Israel's Egypt sojourn
  and the Exodus pattern; Matt 2:13–15 / Hos 11:1 ground "out of Egypt" as
  a Christ-type. Abram's deception is handled honestly — the patriarch's failure
  contrasts with Christ's faithfulness.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ commentary for Genesis 10–12. Ch10 is the table of nations
#   (scope of redemption); ch11 is Babel (reversed at Pentecost) + the genealogy
#   that leads to Abram (Christ's ancestry via Luke 3); ch12 is the Abrahamic
#   covenant (the gospel announced in advance per Gal 3:8).
# CHANGE? If data/commentary/mkt-christ/genesis.json schema changes, update
#   load_comm/save_comm helpers in Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: After running, python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/genesis.json')); print(len(d.get('10',{})), len(d.get('11',{})), len(d.get('12',{})))" should print "32 32 20".

NEW_DATA = {
"10": {
"1": "<p>The toledot of Shem, Ham, and Japheth opens the table of nations &#8212; the account of how the whole earth was populated from Noah&#8217;s three sons. This table is the map over which Christ&#8217;s redemption is drawn: &#8220;you purchased for God persons from every tribe and language and people and nation&#8221; (Rev 5:9). Paul at the Areopagus grounds his proclamation of Christ in this table: &#8220;From one man he made all the nations, that they should inhabit the whole earth&#8230; so that they would seek him and perhaps reach out for him and find him&#8221; (Acts 17:26&#8211;27). The table of nations is the canvas on which the Great Commission is painted.</p>",
"2": "<p>The sons of Japheth &#8212; the northern and western peoples (Medes, Greeks, peoples of Asia Minor and the coastlands). These nations are among those present at Pentecost (Acts 2:9&#8211;11) when the language-division of Babel begins to be reversed by the Spirit of Christ. The Japhethite nations are part of the scope of the Great Commission: &#8220;Go and make disciples of all nations&#8221; (Matt 28:19). The geographic range of Japheth&#8217;s descendants marks the reach of the gospel into Europe and beyond.</p>",
"3": "<p>The sons of Gomer &#8212; peoples of the far north and northeast. These are nations of the known world&#8217;s edge. The gospel&#8217;s commission reaches to &#8220;the ends of the earth&#8221; (Acts 1:8) &#8212; precisely to the most distant peoples catalogued here. Even the most remote of the table-of-nations peoples are within the scope of Christ&#8217;s &#8220;all authority in heaven and on earth&#8221; (Matt 28:18) and his redemptive purpose of gathering &#8220;the full number of the Gentiles&#8221; (Rom 11:25).</p>",
"4": "<p>The sons of Javan &#8212; the Greek peoples, including Tarshish (possibly Spain) and the Kittites (Cyprus and the Mediterranean coastlands). Javan&#8217;s descendants include the Greek-speaking world that becomes the vehicle of the NT&#8217;s proclamation. The Greek language in which the NT is written, the trade routes of the Mediterranean coastlands, the synagogues of the diaspora &#8212; all are the inheritance of the Japhethite-Javanic spread. God&#8217;s providential ordering of the nations (Acts 17:26) placed the Greek world exactly where it was needed for the gospel&#8217;s spread.</p>",
"5": "<p>&#8220;From these the maritime peoples spread out into their territories by their clans within their nations, each with its own language.&#8221; The linguistic diversity of the nations &#8212; already present here before Babel (or reflecting the post-Babel order) &#8212; is the diversity that the Spirit overcomes at Pentecost: &#8220;each one heard their own language being spoken&#8221; (Acts 2:6). The many languages of the nations, which will become the symbol of division at Babel (ch11), become the medium of proclamation at Pentecost. Christ is declared in every tongue; the linguistic diversity of the nations serves the universal reach of the gospel.</p>",
"6": "<p>The sons of Ham &#8212; Egypt, Canaan, Cush, Put. These are the nations that will variously oppress and interact with Israel in the OT narrative. Egypt enslaves Israel; Canaan is the promised land&#8217;s occupant; Cush (Ethiopia) features in Ps 68:31 as a nation that will bring gifts to God. The Ethiopian eunuch in Acts 8 is from Cush &#8212; one of the earliest Gentile converts, explicitly fulfilling Isaiah&#8217;s vision (Isa 56:3&#8211;8) and the Psalm&#8217;s promise. The Hamitic nations are within the scope of the gospel&#8217;s reach from the beginning of Acts.</p>",
"7": "<p>The sons of Cush include Seba, Havilah, Sheba, and Dedan. Sheba and Dedan appear in later prophetic texts as trading nations that will bring tribute to God&#8217;s anointed king: &#8220;The kings of Sheba and Seba will present him gifts. All kings will bow down to him and all nations will serve him&#8221; (Ps 72:10&#8211;11 &#8212; a Messianic psalm). The Queen of Sheba comes to Solomon (1 Kgs 10:1&#8211;13), whom Jesus cites as a type of Gentile seeking wisdom: &#8220;The Queen of the South will rise at the judgment&#8230; and now something greater than Solomon is here&#8221; (Matt 12:42). The nations catalogued here are the nations Psalm 72 promises will serve Christ.</p>",
"8": "<p>Nimrod is the first named &#8220;mighty warrior&#8221; (<em>gibbôr</em>) on earth &#8212; the prototype of imperial power. The contrast with Christ is instructive: Nimrod is &#8220;mighty&#8221; through conquest and kingdom-building; Christ is mighty through self-giving and suffering. Phil 2:6&#8211;9 describes the opposite trajectory: not grasping power but emptying, not building a kingdom by force but receiving it through obedience to death. The one who truly receives the kingdoms of the earth (Rev 11:15 &#8212; &#8220;the kingdom of the world has become the kingdom of our Lord and of his Messiah&#8221;) does so not as a Nimrod but as the Lamb.</p>",
"9": "<p>&#8220;A mighty hunter before the LORD&#8221; &#8212; Nimrod&#8217;s fame is established in a proverb. The image of the hunter is picked up in prophetic texts: Jer 16:16 &#8212; God sending &#8220;hunters&#8221; to pursue Israel into exile. Christ as the Good Shepherd (John 10:11) is the counter-image: not the hunter who pursues prey for conquest, but the shepherd who lays down his life for the sheep. The &#8220;hunter of men&#8221; that Nimrod represents is the template of worldly power; Christ as the one who seeks and saves the lost (Luke 19:10) is the opposite &#8212; not hunting to destroy but seeking to save.</p>",
"10": "<p>The first centers of Nimrod&#8217;s kingdom: Babylon, Uruk, Akkad, and Kalneh in Shinar. Babylon &#8212; the city that begins here &#8212; becomes in Scripture the symbol of human empire in opposition to God (Dan 4; Rev 14:8; 17&#8211;18). The &#8220;fall of Babylon&#8221; in Rev 18 is the decisive defeat of the Nimrod-principle: human civilization organized for self-glorification rather than God&#8217;s glory. Christ is the &#8220;King of kings and Lord of lords&#8221; (Rev 19:16) before whom all Babylons fall. The origin of Babylon here is the origin of everything that will be judged when Christ returns.</p>",
"11": "<p>From Shinar Nimrod builds Nineveh and the Assyrian cities. Nineveh becomes the target of Jonah&#8217;s mission &#8212; and Jesus explicitly uses Jonah&#8217;s three-day experience as a type of his own death and resurrection (Matt 12:40). Nineveh&#8217;s repentance at Jonah&#8217;s preaching is cited by Jesus as a judgment against those who refuse to repent at the proclamation of &#8220;something greater than Jonah&#8221; (Matt 12:41). The great Assyrian city founded by Nimrod&#8217;s extension of power is also the city that repents &#8212; a preview of the Gentile response to the gospel of Christ.</p>",
"12": "<p>Resen between Nineveh and Calah &#8212; &#8220;the great city.&#8221; The description &#8220;great city&#8221; (<em>hāʿîr haggĕḏōlāh</em>) echoes through Jonah (1:2; 3:2; 4:11) and enters Revelation as the designation for Babylon (Rev 11:8; 16:19; 18:10). The contrast between the &#8220;great city&#8221; of human empire (which falls, Rev 18:10) and the New Jerusalem that comes down from God (Rev 21:2 &#8212; a city &#8220;prepared as a bride adorned for her husband&#8221;) is the eschatological counter to everything Nimrod&#8217;s great cities represent. Christ establishes the only city that lasts.</p>",
"13": "<p>Egypt was the father of the Ludites, Anamites, and the other peoples of northeastern Africa and the Mediterranean. Egypt is the nation into which Abraham descends in the famine (12:10), into which Jacob&#8217;s family migrates (ch46), from which the Exodus delivers Israel, and into which the holy family flees (Matt 2:13&#8211;15). The origin of Egypt here is the origin of the nation through which the great Exodus-type of redemption will be worked out &#8212; the type that Paul applies to Christ: &#8220;our ancestors were all under the cloud and&#8230; all passed through the sea&#8221; and &#8220;that rock was Christ&#8221; (1 Cor 10:1&#8211;4).</p>",
"14": "<p>The Kasluhites, from whom the Philistines came, and the Caphtorites. The Philistines &#8212; Israel&#8217;s persistent OT adversaries &#8212; originate in Ham&#8217;s line. Goliath the Philistine is the giant-warrior that David defeats &#8212; and David&#8217;s defeat of Goliath is a type of Christ&#8217;s defeat of the adversary. 1 Sam 17&#8217;s narrative of the champion who fights on behalf of his people is the pattern that Paul applies to Christ in Rom 5:17&#8211;19 and Col 2:15. The Philistines who are the enemy of David and his kingdom trace their origin to this verse.</p>",
"15": "<p>Canaan fathered Sidon and the Hittites. Canaan is the promised land &#8212; the land God promises to Abraham in the next chapter (12:7) and gives to Israel through Joshua. The Canaanite nations listed here are the nations whose land becomes the inheritance of Israel &#8212; and the land promise is the type of the inheritance Christ secures: &#8220;In him we were also chosen, having been predestined according to the plan of him who works out everything&#8230; in order that we might be for the praise of his glory&#8221; (Eph 1:11&#8211;12). The land given to Canaan becomes the land promised to Abraham&#8217;s seed &#8212; who is Christ (Gal 3:16).</p>",
"16": "<p>Jebusites, Amorites, Girgashites &#8212; among the nations occupying Canaan before Israel. The Jebusites held Jerusalem (Jebus) until David captured it and made it his royal city &#8212; the city that becomes the center of the Messianic promise (Ps 2:6; 48:1&#8211;2; 132:13&#8211;14) and the city where Christ is crucified, raised, and from which the gospel goes out (Acts 1:8). The Jebusites&#8217; stronghold that David took becomes the city that Christ enters on Palm Sunday, dies outside its walls, and transforms into the type of the heavenly Jerusalem (Heb 12:22; Rev 21:2).</p>",
"17": "<p>Hivites, Arkites, Sinites &#8212; further Canaanite clans. These are among the seven nations that God will dispossess to give Israel the land (Deut 7:1). The dispossession of the Canaanites is not ethnic cleansing but divine judgment on entrenched wickedness (Gen 15:16 &#8212; &#8220;the sin of the Amorites has not yet reached its full measure&#8221;). The same divine justice that expels the Canaanites will, in Christ, offer them (and all nations) mercy through repentance (Rahab in Josh 2; the Canaanite woman in Matt 15:21&#8211;28). Christ&#8217;s redemption reaches even those nations that stand under judgment.</p>",
"18": "<p>Arvadites, Zemarites, Hamathites &#8212; the northernmost Canaanite clans, with Hamath marking the ideal northern border of the promised land (Num 34:8; 1 Kgs 8:65). The full extent of the Canaanite territory &#8212; from Sidon in the north to the cities of the plain in the south &#8212; is the extent of the inheritance that God promises and that Christ the seed of Abraham ultimately inherits (Gal 3:16, 29). The Canaanite clans scattered across this territory are the peoples over whose land the promise of the seed will be fulfilled.</p>",
"19": "<p>The borders of Canaan reaching toward Sodom and Gomorrah. Sodom and Gomorrah &#8212; which will be destroyed in ch19 &#8212; become in the NT the paradigm of divine judgment against sin. Jesus uses Sodom explicitly as a warning to cities that reject the gospel: &#8220;It will be more bearable for Sodom on the day of judgment than for you&#8221; (Matt 10:15; 11:24). The geography of the Canaanite border that includes Sodom and Gomorrah is the geography of the judgment that Christ&#8217;s coming makes more severe for those who reject it than it was for those ancient cities.</p>",
"20": "<p>The summary of the Hamitic nations &#8212; Ham&#8217;s clans by their languages, territories, and nations. The closing formula emphasizes the diversity of human civilization: clans, languages, territories, nations. This fourfold diversity is exactly the fourfold description of Christ&#8217;s redeemed in Rev 5:9 (&#8220;from every tribe and language and people and nation&#8221;) and Rev 7:9 (&#8220;a great multitude that no one could count, from every nation, tribe, people and language&#8221;). The table of nations ends each section with this formula, as if already anticipating the full harvest that Christ will gather from each category.</p>",
"21": "<p>&#8220;Sons were also born to Shem&#8230; Shem was the ancestor of all the sons of Eber.&#8221; Shem&#8217;s line is the Semitic line &#8212; the line from which Abraham, Israel, and Christ descend. The emphasis that Shem is &#8220;the ancestor of all the sons of Eber&#8221; &#8212; the Hebrews (&#8216;ibrîm from Eber) &#8212; marks this line as the line through which God&#8217;s redemptive purpose will narrow from all humanity to one nation and ultimately to one person. The Semitic line is the line Christ enters: &#8220;a descendant of David according to the flesh&#8221; (Rom 1:3), a Hebrew of Hebrews (Phil 3:5).</p>",
"22": "<p>The sons of Shem include Arphaxad and Aram. Arphaxad is the direct ancestor of Abraham (11:10&#8211;26) and thus of Christ. Luke 3:36 names Arphaxad in the genealogy of Jesus between Shem and Shelah. The Arameans (from Aram) become Israel&#8217;s neighbors and sometimes enemies; Israel&#8217;s confession &#8220;My father was a wandering Aramean&#8221; (Deut 26:5) identifies Aramaic origins. The language of Jesus&#8217; daily speech was Aramaic &#8212; a descendant of Aram&#8217;s influence. The Son of God speaks in the tongue of Aram&#8217;s descendants.</p>",
"23": "<p>The sons of Aram include Uz. The land of Uz is where Job lives (Job 1:1) &#8212; the setting of one of the OT&#8217;s most profound explorations of suffering and divine justice. Job&#8217;s anguish and his cry for a mediator (Job 9:33 &#8212; &#8220;if only there were someone to mediate between us&#8221;) is the cry that Christ answers as the one mediator between God and humanity (1 Tim 2:5). The Aram-Uz connection threads from this genealogical entry to the book of Job to the NT&#8217;s answer to Job&#8217;s desperate hope for a mediator.</p>",
"24": "<p>Arphaxad fathers Shelah; Shelah fathers Eber. Both are named in Luke&#8217;s genealogy of Jesus (Luke 3:35). The name Eber gives the Hebrews their name (<em>ʿibrî</em>) &#8212; the people descended from the line that leads to Abraham and ultimately to Christ. The Hebrew people &#8212; the &#8220;people of Eber&#8221; &#8212; are the people through whom the promise of Genesis 3:15 is carried and through whom Christ enters the world. This genealogical chain is the chain of promise.</p>",
"25": "<p>Peleg &#8212; &#8220;because in his time the earth was divided.&#8221; The division of the earth likely refers to the Babel event of ch11. Luke 3:35 names Peleg in Christ&#8217;s genealogy. The generation of the earth&#8217;s division is represented in Christ&#8217;s ancestry &#8212; Christ comes not despite the division of humanity into nations but through it, and in order to gather what was divided: &#8220;I have other sheep that are not of this sheep pen. I must bring them also&#8221; (John 10:16). The one born of Peleg&#8217;s divided-earth generation will re-unite what was scattered at Babel through the gospel.</p>",
"26": "<p>Joktan&#8217;s line &#8212; the Arabian peoples. Like the other branches of the table of nations, these peoples are within the scope of Christ&#8217;s redemptive reach. The gospel moves into Arabia: Paul went to Arabia after his conversion (Gal 1:17), and the Arabian peoples are implied in the global scope of Acts 1:8 (&#8220;to the ends of the earth&#8221;) and Rev 7:9 (&#8220;every nation, tribe, people and language&#8221;). No branch of the table of nations is outside the scope of the Great Commission.</p>",
"27": "<p>The sons of Joktan continue &#8212; Hadoram, Uzal, Diklah. These are Arabian tribal names. They represent the diversity of the human family that Christ is sent to redeem. The scope of John 3:16 &#8212; &#8220;God so loved the <em>world</em>&#8221; &#8212; is measured by the breadth of the table of nations. Every clan listed in Genesis 10 is within the &#8220;world&#8221; that God loves and that Christ comes to save. The table of nations is the table of the lost who become the found.</p>",
"28": "<p>Obal, Abimael, Sheba &#8212; further Arabian peoples. Sheba recurs in the prophetic literature of the OT as a nation that will honor Israel&#8217;s king: &#8220;May the kings of Sheba and Seba present him gifts; all kings will bow to him, all nations will serve him&#8221; (Ps 72:10&#8211;11). The Queen of Sheba who comes to Solomon is cited by Jesus as a Gentile who sought wisdom and who will testify at the judgment against those who reject &#8220;something greater than Solomon&#8221; (Matt 12:42). Sheba&#8217;s repeated appearance in Messianic prophecy begins with this genealogical entry.</p>",
"29": "<p>Ophir, Havilah, and Jobab &#8212; completing Joktan&#8217;s line. Ophir is famous as the source of Solomon&#8217;s gold (1 Kgs 9:28) &#8212; the wealth of the nations flowing to Jerusalem as a preview of Isa 60:5 and Rev 21:24. Havilah appeared first in Gen 2:11 as the gold-rich land of Eden. The echo of Eden-gold reappearing in this genealogy suggests the creational abundance that is being redistributed across the nations &#8212; and that will finally be gathered into the New Jerusalem when Christ reigns (Rev 21:26 &#8212; &#8220;the glory and honor of the nations will be brought into it&#8221;).</p>",
"30": "<p>The geographic range of Joktan&#8217;s descendants &#8212; from Mesha to Sephar in the eastern hill country. The geographical anchoring of these ancient peoples in real-world space underlines that redemptive history unfolds in the real world. Christ enters the real world &#8212; &#8220;born in Bethlehem of Judea in the days of Herod the king&#8221; (Matt 2:1) &#8212; not a mythological location but a mappable place in the real geography that the table of nations describes. The same God who placed these peoples in their territories sent his Son into a specific territory at a specific time (Gal 4:4).</p>",
"31": "<p>The closing formula for Shem&#8217;s line: &#8220;by their clans and languages, in their territories and nations.&#8221; The fourfold classification &#8212; clans, languages, territories, nations &#8212; is the exact fourfold description of the redeemed in Rev 5:9 and 7:9. The Spirit who inspired Moses to describe the nations in this fourfold way also inspired John to describe Christ&#8217;s redeemed in the same fourfold way &#8212; deliberately showing that the nations catalogued here are the nations gathered under Christ.</p>",
"32": "<p>&#8220;From these the nations spread out over the earth after the flood.&#8221; The summary of the table of nations &#8212; all humanity from Noah&#8217;s three sons. Paul at Athens quotes this moment of divine ordering: &#8220;From one man he made all the nations, that they should inhabit the whole earth; and he marked out their appointed times in history and the boundaries of their lands. God did this so that they would seek him and perhaps reach out for him and find him, though he is not far from any one of us&#8221; (Acts 17:26&#8211;27). The purpose of the spreading of the nations &#8212; divinely ordered even in the post-flood world &#8212; is that they might seek and find God, who sends his Son to be found (John 1:11&#8211;12).</p>"
},
"11": {
"1": "<p>&#8220;The whole world had one language and a common speech.&#8221; The unity of language before Babel is the state that Pentecost partially restores. The Babel narrative (vv1&#8211;9) is the anti-Pentecost: human unity deployed for self-glorification and divine-defiance, resulting in judgment and scattering. Pentecost is the Christological answer: the Spirit of Christ reunites the divided languages not by imposing one tongue but by speaking in all tongues simultaneously (Acts 2:6&#8211;11). The original unified language is not restored; something better is given &#8212; a unity that transcends language through the Spirit of the risen Christ.</p>",
"2": "<p>&#8220;As people moved eastward.&#8221; The eastward movement &#8212; away from Eden, away from God &#8212; is the direction of post-fall humanity throughout Genesis (3:24; 4:16). The people of Shinar move east into the plain and settle there, beginning the project of self-sufficient civilization. Christ&#8217;s mission is the reversal: he moves &#8220;westward&#8221; in the theological geography of Scripture &#8212; from heaven downward to earth, from divine presence into human exile &#8212; in order to bring humanity back from its eastern exile. The incarnation is God coming toward the eastward-moving rebels.</p>",
"3": "<p>&#8220;Come, let us make bricks.&#8221; The human &#8220;let us&#8221; of Babel is the counterfeit of the divine &#8220;let us&#8221; of creation (1:26) and of judgment (11:7). Humanity mimics divine language and divine council to pursue a self-directed project. The contrast is between the divine &#8220;let us make man in our image&#8221; (1:26) &#8212; God as creator giving life to others &#8212; and the human &#8220;let us make bricks&#8221; &#8212; humanity as self-creator building its own security. Christ as the Word through whom creation happened (John 1:3) is the divine &#8220;let us&#8221; who invites all people not to build their own towers but to enter his kingdom (Matt 11:28).</p>",
"4": "<p>&#8220;Let us build ourselves a city&#8230; so that we may make a name for ourselves.&#8221; The Babel project &#8212; self-aggrandizing urbanism as a defense against divine dispersion &#8212; is directly contrasted with God&#8217;s response to Abraham in the very next chapter (12:2 &#8212; &#8220;I will make your name great&#8221;). The name humanity tries to make for itself by force, God gives freely through covenant. The ultimate &#8220;name above every name&#8221; (Phil 2:9) is given to Christ &#8212; not through human achievement but through self-emptying obedience (Phil 2:6&#8211;8). Babel&#8217;s name-making is the anti-gospel; Christ&#8217;s exaltation is its answer.</p>",
"5": "<p>&#8220;But the LORD came down to see the city and the tower the people were building.&#8221; The ironic divine descent &#8212; the tower meant to reach heaven requires God to &#8220;come down&#8221; even to see it. The irony deepens in light of the incarnation: in Christ, God truly comes down &#8212; not to judge a human tower but to enter human life at its lowest point (Phil 2:7&#8211;8). The &#8220;coming down&#8221; at Babel is judgment; the &#8220;coming down&#8221; at Bethlehem is grace. Both are divine descents; only one saves.</p>",
"6": "<p>&#8220;Nothing they plan to do will be impossible for them.&#8221; God&#8217;s assessment of unified human capacity &#8212; not flattery but a recognition that unchecked human self-assertion will reach devastating ends. The same assessment, reversed, applies to those united in Christ: &#8220;I can do all this through him who gives me strength&#8221; (Phil 4:13); &#8220;with God all things are possible&#8221; (Matt 19:26). The capacity that Babel deployed for self-glorification is the capacity that Christ redeems and redirects toward the glory of God and the good of all.</p>",
"7": "<p>&#8220;Come, let us go down and confuse their language.&#8221; The divine &#8220;let us&#8221; of judgment answers the human &#8220;let us&#8221; of pride (vv3&#8211;4). This divine council-language (echoing 1:26) acts to scatter what humanity united wrongly. The reversal comes at Pentecost: &#8220;All of them were filled with the Holy Spirit and began to speak in other tongues as the Spirit enabled them&#8221; (Acts 2:4). Where the divine &#8220;let us&#8221; at Babel confused languages and scattered, the Spirit of the risen Christ descends (Acts 2:1&#8211;4) and unites the scattered nations in proclamation of &#8220;the wonders of God&#8221; (Acts 2:11).</p>",
"8": "<p>The LORD scattered the builders across the whole earth and they stopped building. The city-building project of self-sufficient humanity is interrupted by divine judgment. The city God is building is different: &#8220;he was looking forward to the city with foundations, whose architect and builder is God&#8221; (Heb 11:10 &#8212; of Abraham). The scattered peoples of Babel will be gathered again &#8212; not by human construction but by Christ&#8217;s cross: &#8220;I, when I am lifted up from the earth, will draw all people to myself&#8221; (John 12:32). The divine scattering at Babel is reversed by the divine gathering at Calvary.</p>",
"9": "<p>&#8220;Babel &#8212; because there the LORD confused the language of the whole world.&#8221; Babel (&#8216;confusion&#8217;) is the name of the city that becomes in Scripture the symbol of all human civilization in opposition to God (Rev 14:8; 17&#8211;18 &#8212; &#8220;Babylon the Great&#8221;). The &#8220;fall of Babylon&#8221; in Rev 18 is the fall of the Babel-principle &#8212; all human self-assertion against God. Christ&#8217;s victory over Babylon/Babel is announced by the angel: &#8220;Fallen! Fallen is Babylon the Great!&#8221; (Rev 18:2). The confusion that Babel names will be ended when Christ reigns and every tongue confesses him as Lord (Phil 2:11) &#8212; a different kind of linguistic unity than Babel imagined.</p>",
"10": "<p>The toledot of Shem begins the genealogy that leads from the flood to Abram &#8212; the genealogy that Luke 3:34&#8211;36 traces as the ancestry of Jesus. Shem, one hundred years old two years after the flood, fathers Arphaxad. Each link in this chain is a link in the genealogy of the Messiah. The post-flood genealogy is the narrowing of the line of promise &#8212; from all humanity (ch10) to Shem&#8217;s line (ch11) to Abram (12) to Isaac and Jacob, until the line narrows to one: Jesus of Nazareth, son of Abraham, son of David (Matt 1:1).</p>",
"11": "<p>Shem lives 500 years after Arphaxad&#8217;s birth. The post-flood lifespans begin to decline from the antediluvian figures (Methuselah: 969; Noah: 950) toward shorter spans. The shortening of lifespans across the genealogy reflects the post-flood world&#8217;s changed conditions. The death refrain from ch5 continues &#8212; the mortality that Christ comes to defeat (1 Cor 15:26) persists through every generation of the Messianic genealogy, making the resurrection more urgent with each passing generation. Every death in this genealogy adds to the argument for the resurrection.</p>",
"12": "<p>Arphaxad fathers Shelah at 35 years. Luke 3:35 names Arphaxad in Christ&#8217;s genealogy between Shem and Shelah (Luke uses the LXX&#8217;s &#8220;Cainan&#8221; as an intermediary, following a textual tradition). The genealogy moves at this point from the broad post-flood table toward the narrow Semitic line that leads to Abraham. Each generation is a generation closer to the incarnation &#8212; closer to the moment when the Son of God enters the genealogy as its culmination rather than its continuation.</p>",
"13": "<p>Arphaxad lives 403 years after Shelah&#8217;s birth. The narrowing genealogy continues its slow movement toward Abraham. The centuries between the flood and Abraham&#8217;s call are centuries of patient divine purpose &#8212; God working through the ordinary mechanics of human generation to bring his Son into the world at exactly the right time (Gal 4:4 &#8212; &#8220;when the fullness of time had come&#8221;). The divine patience across these 403 years is the same patience that 2 Pet 3:9 describes as the reason for the delay in Christ&#8217;s return.</p>",
"14": "<p>Shelah fathers Eber at 30 years. Luke 3:35 names Shelah in Christ&#8217;s genealogy. Eber is the eponymous ancestor of the Hebrews (<em>ʿibrîm</em>) &#8212; the name of the people through whom Christ comes. The very name of the Hebrew people, the people of God&#8217;s special covenant revelation, traces to this link in the genealogy. Christ is &#8220;born under the law&#8221; (Gal 4:4) &#8212; born into the Hebrew people whose name begins with Eber.</p>",
"15": "<p>Shelah lives 403 years after Eber&#8217;s birth. The genealogy continues its slow narrowing. The great spans of years in this chain &#8212; Shem to Abram spans roughly 390 years &#8212; represent the long centuries of divine patience and preparation between Noah and the Abrahamic covenant. The God who preserves the genealogical line through these centuries is the God who, &#8220;at just the right time&#8230; demonstrated his righteousness&#8221; through Christ (Rom 3:25&#8211;26). Every year of the genealogy is a year of divine faithfulness.</p>",
"16": "<p>Eber fathers Peleg at 34 years. Luke 3:35 names Eber in Christ&#8217;s genealogy. Peleg&#8217;s generation is when &#8220;the earth was divided&#8221; (10:25) &#8212; likely a reference to Babel&#8217;s linguistic scattering. Christ, who descends from the generation of the earth&#8217;s division, comes to gather what was divided: &#8220;he came and preached peace to you who were far away and peace to those who were near&#8221; (Eph 2:17). The genealogy runs through Peleg&#8217;s divided generation toward the one who unites.</p>",
"17": "<p>Eber lives 430 years after Peleg&#8217;s birth. The 430 years of Eber&#8217;s post-Peleg life is the same figure as Israel&#8217;s time in Egypt (Exod 12:40&#8211;41). The coincidence of numbers may be unintentional but points to the way Scripture&#8217;s numbers often carry typological resonance. The 430 years of Egypt that end with the Exodus &#8212; the paradigmatic redemption of the OT &#8212; is the same span that Eber&#8217;s remaining life covers. The Exodus&#8217;s 430 years is the template that Christ&#8217;s greater exodus (Luke 9:31 &#8212; his &#8220;departure&#8221;) fulfills.</p>",
"18": "<p>Peleg fathers Reu at 30 years. Luke 3:35 names Peleg in Christ&#8217;s genealogy. The genealogy moves from the divided-earth generation toward Abraham. Reu&#8217;s name may mean &#8220;friend&#8221; &#8212; echoing the relationship vocabulary that reaches its fullest expression in Christ: &#8220;I no longer call you servants&#8230; Instead I have called you friends&#8221; (John 15:15). The relational language embedded in these ancient names finds its ultimate expression in Christ&#8217;s redefining of the divine-human relationship as friendship.</p>",
"19": "<p>Peleg lives 209 years after Reu&#8217;s birth. The lifespans continue to shorten &#8212; Peleg&#8217;s total of 239 years is less than half of the antediluvian figures. The shortening of life is the intensification of the mortality that the death refrain announced in ch5. As lifespans shorten, the urgency of Christ&#8217;s victory over death increases. &#8220;Just as people are destined to die once, and after that to face judgment, so Christ was sacrificed once to take away the sins of many&#8221; (Heb 9:27&#8211;28). The trajectory of shortening life points toward the one who enters fully mortal life and defeats death from within.</p>",
"20": "<p>Reu fathers Serug at 32 years. Luke 3:35 names Reu in Christ&#8217;s genealogy. The genealogy is now approximately halfway from Shem to Abram &#8212; the narrowing line moving steadily toward the man through whom God will announce the Messianic covenant. Every name in this genealogy is a name in the family tree of God incarnate. The Son of God will call these ancient names his ancestors &#8212; &#8220;born of the seed of David according to the flesh&#8221; (Rom 1:3) includes this entire pre-Davidic genealogy.</p>",
"21": "<p>Reu lives 207 years after Serug&#8217;s birth. The shortening lifespan continues &#8212; Reu&#8217;s total of 239 years matches Peleg&#8217;s. Each generation brings the line closer to the one who will live only 33 years on earth but accomplish what centuries of long-lived patriarchs could not. The compression of human lifespan across these generations is the compression of the world&#8217;s history toward &#8220;the fullness of time&#8221; (Gal 4:4) when God sends his Son born of a woman.</p>",
"22": "<p>Serug fathers Nahor at 30 years. Luke 3:35 names Serug in Christ&#8217;s genealogy. The chain is nearly complete: Shem &#8594; Arphaxad &#8594; Shelah &#8594; Eber &#8594; Peleg &#8594; Reu &#8594; Serug &#8594; Nahor &#8594; Terah &#8594; Abraham. Three more links remain in the chain from Shem to Abram &#8212; and Abram to Christ is the story of the OT. The genealogy that begins with Shem ends with the man through whom God announces the gospel in advance (Gal 3:8).</p>",
"23": "<p>Serug lives 200 years after Nahor&#8217;s birth. Serug&#8217;s total lifespan is 230 years &#8212; continuing the decline from antediluvian figures. The shortening lives mark the acceleration of history toward its goal: not the end of all things but the coming of the one thing all things point to &#8212; Christ. &#8220;In these last days [God] has spoken to us by his Son&#8221; (Heb 1:2) &#8212; the &#8220;last days&#8221; begin with Christ&#8217;s coming; the genealogy is moving toward those last days with every generation.</p>",
"24": "<p>Nahor fathers Terah at 29 years. Luke 3:34 names Nahor in Christ&#8217;s genealogy. Two more links remain: Terah fathers Abram, and then the Abrahamic covenant is announced. The approach of Abraham in the genealogy is the approach of the covenant that Paul calls &#8220;the gospel announced in advance&#8221; (Gal 3:8). The reader of Luke&#8217;s genealogy knows that every step from Nahor toward Terah toward Abram is a step toward Jesus. The genealogy of Luke 3 is the genealogy of the one who walked through the same world these ancestors knew.</p>",
"25": "<p>Nahor lives 119 years after Terah&#8217;s birth. Nahor&#8217;s total of 148 years is markedly shorter than any of his ancestors &#8212; the life of a man approaching the normal human lifespan of later generations. The world is changing; the genealogy is approaching its historical setting in the second millennium BC. God&#8217;s redemptive purpose moves through the changing conditions of human history &#8212; from the antediluvian world of Noah to the ancient Near East of Abraham &#8212; always faithful to the promise of the seed (3:15).</p>",
"26": "<p>Terah fathers Abram, Nahor, and Haran. The naming of Abram &#8212; the first of Terah&#8217;s sons, and the one through whom the covenant will run &#8212; is the penultimate step in the genealogy from Shem to the Messianic line. Luke 3:34 names Terah in Christ&#8217;s genealogy. The line has narrowed from all humanity (ch10) to Shem&#8217;s descendants (ch11) to Terah&#8217;s family (v26) to Abram alone (ch12) to Isaac (ch21) to Jacob (ch25) to Judah (ch38) &#8212; the progressive narrowing that culminates in the Davidic line and ultimately in Christ.</p>",
"27": "<p>The toledot of Terah: Abram, Nahor, Haran; and Haran&#8217;s son Lot. The family of Terah is the family into which the Abrahamic covenant is about to be announced. Lot &#8212; Abram&#8217;s nephew &#8212; will travel with him and become a foil in the narrative: the man who chooses by sight (Sodom&#8217;s well-watered plain) rather than faith. The contrast between Abram (who walks by faith, Heb 11:8) and Lot (who walks by sight, 2 Cor 5:7&#8217;s negative image) is established in the family structure of this verse.</p>",
"28": "<p>Haran dies in Ur while his father Terah is still alive &#8212; the tragedy of a child dying before a parent. Death does not wait for the proper order of generations; it strikes young and old, in the pre-Abraham world as in every world. The grief of Haran&#8217;s early death is the grief that Christ enters in John 11 when he stands before the tomb of Lazarus and weeps (John 11:35). Christ is &#8220;a man of sorrows, acquainted with grief&#8221; (Isa 53:3) &#8212; acquainted with exactly this kind of grief, the premature death of the beloved that disrupts the expected order of life.</p>",
"29": "<p>Abram marries Sarai; Nahor marries Milcah. The marriages that establish the patriarchal family are the marriages through which the promise will flow. Sarai will be the mother of Isaac, through whom the covenant continues to Jacob and Judah and David and Christ. The marriage of Abram and Sarai is the marriage through which the Messianic line will run &#8212; the marriage Paul uses in Gal 4:21&#8211;31 as an allegory of the two covenants: Hagar/Sinai vs. Sarah/the free Jerusalem, the latter being the covenant of promise through Christ.</p>",
"30": "<p>&#8220;Now Sarai was childless because she was not able to conceive.&#8221; The barrenness of Sarai is the impossible condition that God will overcome to produce the promised heir. The pattern of barren women whose children God provides &#8212; Sarah, Rebekah, Rachel, Hannah, Elizabeth &#8212; reaches its ultimate form in Mary&#8217;s virginal conception of Christ. Each barren womb that God opens is a small step toward the impossible birth that defeats death itself. Paul in Gal 4:27 quotes Isa 54:1 (&#8220;Rejoice, you who are barren&#8221;) and applies it to the Jerusalem above &#8212; the church born of grace, not human generation &#8212; exactly as Isaac was born of Sarai&#8217;s impossible conception.</p>",
"31": "<p>Terah sets out from Ur of the Chaldeans toward Canaan &#8212; but stops at Haran. The journey toward the promised land begins with Terah but is only completed when Abram obeys God&#8217;s call (12:4). Heb 11:8 says Abram obeyed &#8220;even though he did not know where he was going&#8221; &#8212; the model of faith-obedience that Christ embodies perfectly: &#8220;not as I will, but as you will&#8221; (Matt 26:39). The incomplete journey of Terah (he stops at Haran and dies there) is completed by the son who trusts God&#8217;s word rather than settling for the comfortable interim stop.</p>",
"32": "<p>Terah lives 205 years and dies in Haran &#8212; short of the promised land. The death of Terah in Haran &#8212; having set out for Canaan but not arrived &#8212; is the pattern of OT faith: &#8220;these were all commended for their faith, yet none of them received what had been promised&#8221; (Heb 11:39). Terah dies in sight of the promise. The faith that Abram will embody &#8212; leaving Haran after his father&#8217;s death (Acts 7:4) &#8212; is the faith that presses on past the place where others stop. Christ is the one who arrives at the destination that Terah died short of: &#8220;the city with foundations, whose architect and builder is God&#8221; (Heb 11:10).</p>"
},
"12": {
"1": "<p>&#8220;The LORD had said to Abram, &#8216;Go from your country, your people and your father&#8217;s household to the land I will show you.&#8217;&#8221; The call of Abram is the decisive moment when the narrow line of promise becomes an explicit divine commission. Heb 11:8 reads this verse as the model of faith: &#8220;by faith Abraham, when called to go to a place he would later receive as his inheritance, obeyed and went, even though he did not know where he was going.&#8221; Christ is the fulfillment of this call: he leaves the Father&#8217;s household (John 16:28 &#8212; &#8220;I came from the Father and entered the world&#8221;) to go to the place the Father shows him, trusting even through Gethsemane and Calvary. The obedience of Abram is the shadow of the obedience of Christ.</p>",
"2": "<p>&#8220;I will make you into a great nation, and I will bless you; I will make your name great, and you will be a blessing.&#8221; The threefold promise &#8212; nation, blessing, great name &#8212; stands in direct contrast to Babel&#8217;s failed project (11:4 &#8212; &#8220;let us make a name for ourselves&#8221;). What humanity tried to seize at Babel, God gives freely through covenant to Abram. The &#8220;great name&#8221; promised here ultimately refers to Christ: &#8220;God exalted him to the highest place and gave him the name that is above every name&#8221; (Phil 2:9). The blessing that Abram receives and becomes flows to all nations through Jesus, &#8220;the son of Abraham&#8221; (Matt 1:1).</p>",
"3": "<p>&#8220;All peoples on earth will be blessed through you.&#8221; Paul identifies this verse as the gospel announced in advance: &#8220;Scripture foresaw that God would justify the Gentiles by faith, and announced the gospel in advance to Abraham: &#8216;All nations will be blessed through you.&#8217;&#8221; (Gal 3:8). Paul also identifies &#8220;your seed&#8221; as Christ: &#8220;the promises were spoken to Abraham and to his seed. Scripture does not say &#8216;and to seeds,&#8217; meaning many people, but &#8216;and to your seed,&#8217; meaning one person, who is Christ&#8221; (Gal 3:16). John 8:56 &#8212; &#8220;your father Abraham rejoiced at the thought of seeing my day; he saw it and was glad&#8221; &#8212; confirms that Abraham himself understood the Messianic depth of this promise. This verse is the founding charter of the gospel.</p>",
"4": "<p>&#8220;So Abram went, as the LORD had told him.&#8221; The obedience is immediate and total &#8212; no recorded hesitation, no negotiation. Heb 11:8 &#8212; &#8220;by faith Abraham obeyed and went&#8221; &#8212; identifies this as the paradigm of faith. Christ&#8217;s obedience is the antitype: &#8220;he humbled himself by becoming obedient to death&#8212; even death on a cross&#8221; (Phil 2:8). Abram goes to an unknown land; Christ goes to a known destination &#8212; the cross &#8212; without turning back (Luke 9:51 &#8212; &#8220;he set his face resolutely toward Jerusalem&#8221;). The faith that moves at God&#8217;s word without knowing the full path is the faith that characterizes the Son who does only what the Father shows him (John 5:19).</p>",
"5": "<p>Abram takes Sarai, Lot, and all his possessions and people out of Haran and sets out for Canaan &#8212; arriving there. The completed journey &#8212; Haran to Canaan &#8212; that Terah began but did not finish (11:31) is completed by the one who trusts God&#8217;s word. The arrival in Canaan marks the beginning of the sojourner-life that Heb 11:9 describes: &#8220;by faith he made his home in the promised land like a stranger in a foreign country.&#8221; Christ as the ultimate sojourner &#8212; &#8220;the Son of Man has no place to lay his head&#8221; (Matt 8:20) &#8212; lives exactly this pilgrim existence, &#8220;tabernacling&#8221; among us (John 1:14) as a stranger in his own world (John 1:11).</p>",
"6": "<p>Abram travels to Shechem and the tree of Moreh. Shechem is where Jacob will buy land (33:19) and where Joseph will be buried (Josh 24:32) &#8212; a site of Patriarchal significance. Most strikingly, Shechem is where Jesus sits at Jacob&#8217;s well and speaks to the Samaritan woman (John 4:5&#8211;6). Jesus claims the same ground Abram traversed &#8212; standing at Shechem as the one who gives living water (John 4:14), fulfilling the promise made to Abraham at this very location. The tree of Moreh (&#8220;teacher&#8221;) prefigures the great teacher who sits at Shechem&#8217;s well and reveals himself as the Messiah (John 4:25&#8211;26).</p>",
"7": "<p>&#8220;To your offspring I will give this land.&#8221; The land promise is explicitly applied to Christ in Gal 3:16: &#8220;the promises were spoken to Abraham and to his seed&#8230; meaning one person, who is Christ.&#8221; The land that God promises to Abram&#8217;s seed is the type of the inheritance Christ secures &#8212; not merely the territory of Canaan but &#8220;an inheritance that can never perish, spoil or fade&#8221; (1 Pet 1:4). Abram builds an altar in response; the response to the divine appearance is worship. Christ is both the object of worship and the one through whom worshipers approach God (John 4:23&#8211;24; Heb 10:19&#8211;22).</p>",
"8": "<p>Abram pitches his tent between Bethel and Ai and builds an altar, calling on the name of the LORD. Bethel &#8212; &#8220;house of God&#8221; &#8212; is where Jacob will later see the ladder to heaven (28:12). Jesus applies that Bethel vision to himself: &#8220;you will see heaven open, and the angels of God ascending and descending on the Son of Man&#8221; (John 1:51). Christ is the true Bethel &#8212; the house of God, the place where heaven and earth meet. Abram&#8217;s altar at Bethel is the altar at the type; Christ is the altar, priest, and sacrifice at the antitype (Heb 13:10).</p>",
"9": "<p>Abram journeys southward toward the Negev &#8212; moving through the land of promise as a sojourner. The Negev is the arid south country, a land of sparse resources. Abram&#8217;s continued movement through the land without possessing it is the sojourner-faith of Heb 11:9 &#8212; he inherits the land as a pilgrim who trusts the giver rather than grasping the gift. Christ&#8217;s own ministry moves through the land of promise &#8212; Galilee, Samaria, Judea &#8212; as one who has no permanent home (Matt 8:20), inhabiting the land of promise as its Lord but not exploiting it for personal security.</p>",
"10": "<p>Famine drives Abram to Egypt. The pattern of famine &#8594; Egypt &#8594; deliverance recurs in Genesis (Jacob in ch46) and becomes the paradigmatic type of Israel&#8217;s redemption through the Exodus. Matthew makes the Christ-connection explicit: the holy family&#8217;s flight to Egypt fulfills Hos 11:1 &#8212; &#8220;out of Egypt I called my son&#8221; (Matt 2:15). As Israel goes down to Egypt in famine and comes up as God&#8217;s redeemed son, so Jesus goes down to Egypt as an infant and comes up from Egypt as the Son of God who will lead the new exodus. The famine that sends Abram to Egypt begins the Egypt-pattern that Christ recapitulates and fulfills.</p>",
"11": "<p>Abram&#8217;s recognition of Sarai&#8217;s beauty anticipates the danger he is about to navigate through deception rather than trust. The contrast with Christ is implicit: Christ, who faces genuine danger &#8212; the threat of arrest, torture, and death &#8212; does not dissemble or seek a path of self-preservation. He &#8220;entrusted himself to him who judges justly&#8221; (1 Pet 2:23). The patriarch who fears for his life and protects himself through a half-truth is the shadow-figure of the Son who faces death without flinching and without deception, trusting the Father&#8217;s vindication.</p>",
"12": "<p>Abram&#8217;s fear &#8212; &#8220;they will kill me but will let you live.&#8221; The fear of death that drives Abram&#8217;s deception is the fear that Christ&#8217;s resurrection destroys. Heb 2:14&#8211;15 says Christ took on flesh and blood &#8220;so that by his death he might break the power of him who holds the power of death &#8212; that is, the devil &#8212; and free those who all their lives were held in slavery by their fear of death.&#8221; Abram&#8217;s fear of Egyptian execution is the slavery to the fear of death from which Christ liberates his people &#8212; by enduring the death they fear and rising beyond it.</p>",
"13": "<p>&#8220;Say you are my sister, so that I will be treated well for your sake.&#8221; Abram&#8217;s deception &#8212; Sarai is his half-sister (20:12), so it is a half-truth deployed as a full lie &#8212; is the patriarchal failure that endangers the covenant promise. The contrast with Christ is stark: &#8220;No deceit was found in his mouth&#8221; (1 Pet 2:22, citing Isa 53:9). Christ as the faithful Son does not protect himself through deception &#8212; he speaks the full truth before Pilate even when silence or a partial truth might have saved him (John 18:36&#8211;37; 19:11). The truthfulness of the last Adam contrasts with the deception of Abram.</p>",
"14": "<p>The Egyptians see Sarai&#8217;s beauty and she is taken to Pharaoh&#8217;s court. The threat to the covenant line &#8212; Sarai taken by Pharaoh, the promised heir still unborn &#8212; is resolved not by Abram&#8217;s cleverness but by God&#8217;s intervention (v17). The pattern established here &#8212; the covenant promise endangered by human failure but preserved by divine faithfulness &#8212; is the pattern of God&#8217;s entire redemptive plan. Human failure at every turn threatens what God has promised; God&#8217;s faithfulness at every turn preserves it. Christ is the ultimate expression of that divine faithfulness: &#8220;for no matter how many promises God has made, they are &#8216;Yes&#8217; in Christ&#8221; (2 Cor 1:20).</p>",
"15": "<p>Pharaoh&#8217;s officials praise Sarai and she is brought into the royal palace. The one through whom the Messianic promise flows is in the hands of a foreign king &#8212; a precarious situation that God will resolve. The same pattern unfolds throughout the OT: the righteous one is given into the hands of enemies (Joseph in Potiphar&#8217;s house, Daniel in Babylon) only for God to vindicate them. The ultimate vindication is Christ&#8217;s: handed over to Pilate and crucified, he is raised on the third day. The &#8220;handing over&#8221; that looks like defeat becomes the mechanism of salvation.</p>",
"16": "<p>Pharaoh treats Abram well for Sarai&#8217;s sake &#8212; sheep, cattle, donkeys, servants, camels. The wealth Abram accumulates in Egypt he will bring out with him &#8212; a preview of the Israelite exodus, when Israel &#8220;plunders&#8221; Egypt (Exod 12:35&#8211;36). The transfer of Egyptian wealth into the hands of God&#8217;s people is the pattern of the Exodus, which Paul applies to Christ&#8217;s victory: &#8220;he made a public spectacle of them, triumphing over them by the cross&#8221; (Col 2:15). The enemy&#8217;s wealth serves God&#8217;s purpose in the end.</p>",
"17": "<p>&#8220;The LORD inflicted serious diseases on Pharaoh and his household because of Abram&#8217;s wife Sarai.&#8221; God protects the covenant line even when the covenant man has endangered it through his own failure. This is the revelation of God&#8217;s character that the NT presents fully in Christ: &#8220;if we are faithless, he remains faithful, for he cannot disown himself&#8221; (2 Tim 2:13). The plagues on Pharaoh&#8217;s household foreshadow the ten plagues on Egypt that deliver Israel &#8212; and both point to the pattern of God&#8217;s intervention to rescue his people from the power of a foreign king, fulfilled ultimately in Christ&#8217;s deliverance from sin&#8217;s reign.</p>",
"18": "<p>Pharaoh&#8217;s rebuke of Abram &#8212; &#8220;What have you done to me? Why didn&#8217;t you tell me she was your wife?&#8221; &#8212; is the moral rebuke of a Gentile king directed at the patriarch of the covenant. The irony of Pharaoh rebuking Abram for deception is a foretaste of the OT&#8217;s recurring theme: the nations sometimes act more honorably than God&#8217;s covenant people, which makes the covenant people&#8217;s failure to embody the blessing of v3 more glaring. This is the context Paul has in mind in Rom 2:24 &#8212; &#8220;God&#8217;s name is blasphemed among the Gentiles because of you.&#8221; Christ, the true Israel, does not bring such shame on God&#8217;s name.</p>",
"19": "<p>&#8220;Here is your wife. Take her and go!&#8221; Pharaoh restores Sarai and expels Abram. The restoration of the patriarch&#8217;s wife &#8212; and thus the covenant line &#8212; is not Abram&#8217;s achievement but God&#8217;s. The pattern of exile and restoration established here (Abram goes to Egypt, fails, is expelled but leaves with his wife and wealth) is the pattern of Israel&#8217;s entire history: exile to Babylon, failure, return by God&#8217;s intervention. Christ is the culmination of this return: &#8220;he was delivered over to death for our sins and was raised to life for our justification&#8221; (Rom 4:25). The restoration that follows the crisis is always God&#8217;s doing, not the covenant person&#8217;s.</p>",
"20": "<p>Pharaoh sends Abram away with Sarai and all his possessions. The departure from Egypt with wealth recalls the Exodus pattern &#8212; and the NT applies the Exodus to Christ&#8217;s death and resurrection (Luke 9:31 uses <em>exodon</em> for Christ&#8217;s &#8220;departure&#8221; at Jerusalem; 1 Cor 10:2&#8211;4 reads the Exodus through Christ). Abram leaves Egypt enriched; Christ leaves death triumphant. The pattern of going down to Egypt and coming up leads from Abram through Israel through Jesus &#8212; each exit from Egypt is an exodus, and each exodus points toward the final exodus that Christ accomplishes by passing through death and coming out the other side as the risen Lord.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'genesis', existing)
    print(f"  ch10 verses: {len(existing.get('10', {}))}")
    print(f"  ch11 verses: {len(existing.get('11', {}))}")
    print(f"  ch12 verses: {len(existing.get('12', {}))}")
    print("Genesis 10–12 mkt-christ written.")

if __name__ == '__main__':
    main()
